import { Eye, GitBranch, Sparkles, Loader2, CheckCircle2 } from 'lucide-react';

type MobileTab = 'preview' | 'nodes' | 'ai';
type MobileStep = 'idle' | 'loading' | 'done';

interface MobileNavProps {
  activeTab: MobileTab;
  onTabChange: (tab: MobileTab) => void;
  /** 是否锁定导航（处理中时禁止切换） */
  locked?: boolean;
  /** 当前工作流步骤 */
  step?: MobileStep;
}

const tabs: { key: MobileTab; label: string; icon: React.ElementType }[] = [
  { key: 'preview', label: '预览', icon: Eye },
  { key: 'nodes', label: '节点', icon: GitBranch },
  { key: 'ai', label: 'AI', icon: Sparkles },
];

export default function MobileNav({ activeTab, onTabChange, locked = false, step = 'idle' }: MobileNavProps) {
  const isLoading = step === 'loading';

  return (
    <nav className="lg:hidden h-14 bg-studio-panel/95 backdrop-blur-lg border-t border-studio-border flex items-center justify-around px-2 safe-area-inset-bottom shrink-0 relative">
      {tabs.map(({ key, label, icon: Icon }) => {
        const isActive = activeTab === key;
        return (
          <button
            key={key}
            onClick={() => !locked && onTabChange(key)}
            className={`flex flex-col items-center justify-center gap-0.5 flex-1 py-1 rounded-lg transition-all relative ${
              locked && !isActive
                ? 'text-studio-text-muted/40 cursor-wait'
                : isActive
                  ? 'text-studio-accent'
                  : 'text-studio-text-muted hover:text-studio-text-dim'
            }`}
          >
            {/* 加载中的 AI tab 显示旋转图标 */}
            {isLoading && key === 'ai' ? (
              <Loader2 size={20} strokeWidth={2} className="animate-spin text-studio-warning" />
            ) : (
              <Icon
                size={20}
                strokeWidth={isActive ? 2.2 : 1.8}
                // 完成时 AI 图标变绿
                className={step === 'done' && key === 'ai' ? 'text-studio-success' : ''}
              />
            )}
            <span className={`text-[10px] font-medium ${isActive ? '' : ''}`}>
              {label}
            </span>
            {/* 活动指示条 */}
            {isActive && (
              <div className={`absolute bottom-0.5 left-1/2 -translate-x-1/2 w-5 h-0.5 rounded-full transition-colors ${
                isLoading ? 'bg-studio-warning animate-pulse' : 'bg-studio-accent'
              }`} />
            )}
          </button>
        );
      })}

      {/* 处理中的全局遮罩提示 */}
      {isLoading && (
        <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-studio-warning/90 text-black text-[10px] font-mono px-3 py-1 rounded-full shadow-lg animate-pulse whitespace-nowrap">
          AI 分析中，请稍候...
        </div>
      )}
    </nav>
  );
}
