import { useCallback, useRef } from 'react';
import { useImageStore } from '../store/useImageStore';
import { analyzeAndGrade, type AutoGradeResult } from '../ai/agnes/imageAnalyzer';

export interface ImageLoadResult {
  /** AI 分析结果 */
  analysis: AutoGradeResult['analysis'];
  /** AI 自动生成的调色命令（调用方用于自动创建节点） */
  commands: AutoGradeResult['commands'];
  /** AI 推理过程 */
  reasoning?: string;
  /** 是否为降级结果（AI 分析失败时的 fallback） */
  isFallback?: boolean;
}

/** 最大重试次数（针对网络超时等可恢复错误） */
const MAX_RETRIES = 5;
/** 重试延迟基数（ms），每次重试翻倍 */
const RETRY_BASE_DELAY = 1500;

/** 根据下载进度百分比返回对应的阶段描述 */
function getAnalysisStage(pct: number): string {
  if (pct < 15) return '正在连接 Agnes AI...';
  if (pct < 35) return 'AI 正在分析图像内容...';
  if (pct < 60) return 'AI 正在识别场景与色彩...';
  if (pct < 85) return '正在生成调色方案...';
  return '正在整理分析结果...';
}

/** 判断错误是否可重试（网络超时、服务端 5xx 等） */
function isRetryableError(error: unknown): boolean {
  if (error instanceof Error) {
    const msg = error.message.toLowerCase();
    // 网络超时、连接中断、服务端错误
    if (msg.includes('timeout') || msg.includes('network') || msg.includes('fetch') ||
        msg.includes(' aborted') || msg.includes('failed to fetch')) {
      return true;
    }
    // API 5xx 错误
    if (msg.includes('api 请求失败 (5')) return true;
    // 频率限制
    if (msg.includes('429') || msg.includes('频率')) return true;
  }
  return false;
}

export function useImageLoader() {
  const {
    setImage, setAnalysisResult, setLoading,
    setUploadProgress, setAnalysisProgress, setCurrentStage, setAiError,
  } = useImageStore();
  const fileInputRef = useRef<HTMLInputElement>(null);
  // 缓存上一次的原始图像数据，用于重试 AI 分析（无需重新上传图片）
  const cachedOriginalData = useRef<ImageData | null>(null);

  /**
   * 加载图片 + 触发 AI 自动分析调色
   *
   * 进度分配：
   *   0 - 30%   读取图片文件（FileReader onprogress 真实字节进度）
   *   30 - 40%  图片解码 & 提取像素数据
   *   40 - 95%  AI 分析（ReadableStream 真实网络下载进度）
   *   95 - 100% 解析响应 & 完成
   */
  const loadImage = useCallback(async (file: File): Promise<ImageLoadResult> => {
    const fallbackResult: ImageLoadResult = {
      analysis: {
        sceneType: 'other',
        dominantColors: ['#888888'],
        brightness: 'normal',
        contrastLevel: 'medium',
        suggestions: ['图片已加载，等待 AI 分析...'],
      },
      commands: [],
    };

    setLoading(true);
    setAiError(null); // 清除之前的错误
    setUploadProgress(0);
    setAnalysisProgress(0);
    setCurrentStage('正在读取图片...');

    try {
      // ========== 阶段 1: 读取图片文件 (0-30%, FileReader 真实进度) ==========
      const dataUrl = await new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
          setUploadProgress(30);
          resolve(reader.result as string);
        };
        reader.onerror = reject;
        reader.onprogress = (e: ProgressEvent) => {
          if (e.lengthComputable && e.total > 0) {
            const pct = Math.round((e.loaded / e.total) * 30); // 映射到 0-30%
            setUploadProgress(pct);
            if (pct > 5) setCurrentStage(`正在读取图片 ${pct}%`);
          }
        };
        reader.readAsDataURL(file);
      });

      // ========== 阶段 2: 解码图片 (30-40%) ==========
      setCurrentStage('正在解码图片...');
      setUploadProgress(35);

      const img = await new Promise<HTMLImageElement>((resolve, reject) => {
        const image = new Image();
        image.onload = () => { setUploadProgress(40); resolve(image); };
        image.onerror = reject;
        image.src = dataUrl;
      });

      // 绘制到 canvas 获取 ImageData
      const canvas = document.createElement('canvas');
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d', { willReadFrequently: true })!;
      ctx.drawImage(img, 0, 0);
      const originalImageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const currentImageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

      // 保存图像数据到 store（立即显示预览）
      setImage({
        originalImageData,
        currentImageData,
        width: canvas.width,
        height: canvas.height,
        fileName: file.name,
      });

      // 缓存原始图像数据，用于后续重试 AI 分析
      cachedOriginalData.current = originalImageData;

      setUploadProgress(100); // 上传阶段完成

      // ========== 阶段 3: AI 分析 (40-95%, ReadableStream 真实网络进度) + 自动重试 ==========
      setCurrentStage('正在连接 Agnes AI...');
      setAnalysisProgress(42);

      // 创建 onProgress 回调：将 (loaded/total) 映射到 40-95% 区间
      const onProgress = (loaded: number, total: number) => {
        const rawPct = Math.min(loaded / Math.max(total, 1), 1); // 0-1 原始比例
        // 映射到 42%-93%，留首尾空间给"连接中"和"完成"
        const mappedPct = 42 + rawPct * 51; // 42 → 93
        setAnalysisProgress(Math.round(mappedPct));
        setCurrentStage(getAnalysisStage(rawPct * 100));
      };

      let aiResult: AutoGradeResult;
      let lastError: unknown = null;

      // 带重试的 AI 分析调用
      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          if (attempt > 0) {
            const delay = RETRY_BASE_DELAY * Math.pow(2, attempt - 1);
            setCurrentStage(`AI 分析失败，${delay / 1000}s 后重试 (${attempt}/${MAX_RETRIES})...`);
            setAnalysisProgress(40); // 重置进度
            await new Promise(r => setTimeout(r, delay));
            setCurrentStage(`正在重新连接 Agnes AI... (第 ${attempt + 1} 次)`);
            setAnalysisProgress(42);
          }

          aiResult = await analyzeAndGrade(originalImageData, onProgress);
          lastError = null;
          break; // 成功，退出重试循环

        } catch (err) {
          lastError = err;
          console.warn(`[useImageLoader] AI 分析第 ${attempt + 1} 次尝试失败:`, err);

          // 如果是最后一次重试或不可重试的错误，直接抛出
          if (attempt === MAX_RETRIES || !isRetryableError(err)) {
            throw err;
          }
        }
      }

      // 如果所有重试都失败了（理论上不会走到这里，但作为安全网）
      if (lastError) {
        throw lastError;
      }

      // ========== 阶段 4: 完成 (95-100%) ==========
      setAnalysisProgress(96);
      setCurrentStage('正在解析结果...');
      // 微小延迟让用户看到"解析中"状态
      await new Promise(r => setTimeout(r, 80));
      setAnalysisProgress(100);
      setCurrentStage('分析完成');

      // 保存分析结果到 store
      setAnalysisResult(aiResult.analysis);

      return {
        analysis: aiResult.analysis,
        commands: aiResult.commands,
        reasoning: aiResult.reasoning,
      };

    } catch (error) {
      console.error('[useImageLoader] 图片加载或分析失败:', error);

      const errorMsg = error instanceof Error ? error.message : '未知错误';
      // 标记 AI 错误状态（图片已加载但 AI 失败）
      setAiError(errorMsg);

      setAnalysisResult({
        sceneType: 'other',
        dominantColors: ['#888888'],
        brightness: 'normal',
        contrastLevel: 'medium',
        suggestions: [
          '图片已成功加载',
          `AI 分析失败: ${errorMsg.slice(0, 80)}`,
          isRetryableError(error) ? '可能是网络不稳定，请稍后重试' : '您可以手动添加调色节点',
        ],
      });

      return { ...fallbackResult, isFallback: true };

    } finally {
      setLoading(false);
    }
  }, [setImage, setAnalysisResult, setLoading, setUploadProgress, setAnalysisProgress, setCurrentStage, setAiError]);

  /**
   * 重试 AI 分析（使用缓存的原始图像，无需重新上传）
   * 用于图片已加载但 AI 分析失败的场景
   */
  const retryAnalysis = useCallback(async (): Promise<ImageLoadResult | null> => {
    if (!cachedOriginalData.current) return null;

    const fallbackResult: ImageLoadResult = {
      analysis: {
        sceneType: 'other',
        dominantColors: ['#888888'],
        brightness: 'normal',
        contrastLevel: 'medium',
        suggestions: ['图片已加载，等待 AI 分析...'],
      },
      commands: [],
    };

    setLoading(true);
    setAiError(null);
    setAnalysisProgress(0);
    setCurrentStage('正在重新连接 Agnes AI...');

    try {
      setAnalysisProgress(42);

      const onProgress = (loaded: number, total: number) => {
        const rawPct = Math.min(loaded / Math.max(total, 1), 1);
        const mappedPct = 42 + rawPct * 51;
        setAnalysisProgress(Math.round(mappedPct));
        setCurrentStage(getAnalysisStage(rawPct * 100));
      };

      let aiResult: AutoGradeResult;
      let lastError: unknown = null;

      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        try {
          if (attempt > 0) {
            const delay = RETRY_BASE_DELAY * Math.pow(2, attempt - 1);
            setCurrentStage(`重试中，${delay / 1000}s 后第 ${attempt + 1} 次尝试...`);
            setAnalysisProgress(40);
            await new Promise(r => setTimeout(r, delay));
            setCurrentStage(`正在重新连接 Agnes AI...`);
            setAnalysisProgress(42);
          }

          aiResult = await analyzeAndGrade(cachedOriginalData.current, onProgress);
          lastError = null;
          break;

        } catch (err) {
          lastError = err;
          if (attempt === MAX_RETRIES || !isRetryableError(err)) throw err;
        }
      }

      if (lastError) throw lastError;

      setAnalysisProgress(96);
      setCurrentStage('正在解析结果...');
      await new Promise(r => setTimeout(r, 80));
      setAnalysisProgress(100);
      setCurrentStage('分析完成');
      setAnalysisResult(aiResult.analysis);

      return {
        analysis: aiResult.analysis,
        commands: aiResult.commands,
        reasoning: aiResult.reasoning,
      };

    } catch (error) {
      console.error('[useImageLoader] 重试 AI 分析失败:', error);
      const errorMsg = error instanceof Error ? error.message : '未知错误';
      setAiError(errorMsg);

      setAnalysisResult({
        sceneType: 'other',
        dominantColors: ['#888888'],
        brightness: 'normal',
        contrastLevel: 'medium',
        suggestions: [
          '图片已成功加载',
          `AI 分析仍然失败: ${errorMsg.slice(0, 80)}`,
          isRetryableError(error) ? '网络可能不稳定，请稍后再试' : '您可以手动添加调色节点',
        ],
      });

      return { ...fallbackResult, isFallback: true };

    } finally {
      setLoading(false);
    }
  }, [setLoading, setAiError, setAnalysisProgress, setCurrentStage, setAnalysisResult]);

  const triggerFileInput = useCallback(() => {
    fileInputRef.current?.click();
  }, []);

  return { loadImage, retryAnalysis, triggerFileInput, fileInputRef };
}

export default useImageLoader;
